sys_security_acl.script:
try {
	var user = gs.getUser();
	var userId = user.getID();
	var onbehalfof = current.on_behalf_of;
	var requesterCheck = (current.u_task_requester == userId);
	var assignedCheck = (current.assigned_to == userId);
	var parentAssignedCheck = (current.parent.assigned_to == userId);
	var globalTaCheck =  user.hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");
	var isUserTaskingAuth = function(o,u) {
		var grMembers = new GlideAggregate('x_153465_discovert_discover_office_members');
		grMembers.addQuery('discover_office_hierarchy', o);
		grMembers.addQuery('office_member', u);
		grMembers.addQuery('office_task_authority', 'true');
		// RAJ - STRY0011695 - change to use Glide Aggregate
		grMembers.addAggregate('COUNT');

		grMembers.query();
		var ans = false;
		if(grMembers.next()){
			// RAJ - STRY0011695 - change to use Glide Aggregate
			if (grMembers.getAggregate('COUNT') > 0){
				ans = true;
			}
		}
		return ans;
	};
	var primaryOfficeCheck = (current.primary_office && isUserTaskingAuth(current.primary_office, userId));
	var primaryAssigneeOUCheck = (current.parent.primary_assignee && isUserTaskingAuth(current.parent.primary_assignee,userId));
	var onBehalfOfCheck = (onbehalfof && (onbehalfof == userId));
	if(current.parent) {
		answer = assignedCheck || parentAssignedCheck || primaryAssigneeOUCheck || globalTaCheck;
	} else {
		answer = requesterCheck || assignedCheck || primaryOfficeCheck || onBehalfOfCheck
		|| globalTaCheck;
	}
}catch(e){
	gs.error(e);
	answer = false;
}
